import { SERVICES } from "../constants";

export default function FormPanel({ form, setForm, editing, onSubmit, onCancel }) {

  const handleChange = (field) => (e) => {
    setForm((prev) => ({ ...prev, [field]: e.target.value }));
  };

  return (
    <aside className="pb-sidebar" style={{ padding: '20px', background: '#fff' }}>
      <h2>{editing ? "Editar" : "Novo Agendamento"}</h2>

      {/* NOME */}
      <div style={{ marginBottom: '15px' }}>
        <label>Nome do Cliente</label>
        <input
          className="pb-input"
          style={{ width: '100%', padding: '8px', display: 'block' }}
          value={form.name || ""}
          onChange={handleChange("name")}
          placeholder="Ex: João Silva"
        />
      </div>

      {/* SERVIÇO */}
      <div style={{ marginBottom: '15px' }}>
        <label>Serviço</label>
        <select
          className="pb-select"
          style={{ width: '100%', padding: '8px', display: 'block' }}
          value={form.service || ""}
          onChange={handleChange("service")}
        >
          <option value="">Selecione...</option>
          {SERVICES.map((s) => (
            <option key={s} value={s}>{s}</option>
          ))}
        </select>
      </div>

      {/* DATA E HORA - OS QUE ESTAVAM FALTANDO */}
      <div style={{ marginBottom: '15px' }}>
        <label>Data e Hora</label>
        <div style={{ display: 'flex', gap: '10px' }}>
          <input
            type="date"
            style={{ width: '50%', padding: '8px' }}
            value={form.date || ""}
            onChange={handleChange("date")}
          />
          <input
            type="time"
            style={{ width: '50%', padding: '8px' }}
            value={form.time || ""}
            onChange={handleChange("time")}
          />
        </div>
      </div>

      <button 
        onClick={onSubmit} 
        style={{ 
          padding: '10px 20px', 
          cursor: 'pointer', 
          background: '#FDE047', 
          border: 'none', 
          fontWeight: 'bold',
          width: '100%' 
        }}
      >
        {editing ? "Salvar Alterações" : "Confirmar Agendamento"}
      </button>

      {editing && (
        <button 
          onClick={onCancel} 
          style={{ width: '100%', marginTop: '10px', background: 'transparent', border: '1px solid #ccc' }}
        >
          Cancelar
        </button>
      )}
    </aside>
  );
}
